import { Routes } from '@angular/router';


export const PdfaRoutes: Routes = [
  {
    path: '',
    loadComponent: () => import('./pdfa.component').then((m) => m.PdfaComponent),
    children: [
      {
        path: 'bankForm',
        loadComponent: () =>
          import('./bank-form/bank-form.component').then(
            (m) => m.BankFormComponent
          ),
      },
      {
        path: 'returnPda',
        loadComponent: () =>
          import('./return-pda/return-pda.component').then(
            (m) => m.ReturnPdaComponent
          ),
      },
      {
        path: 'reviewContinue',
        loadComponent: () =>
          import('./review-continue/review-continue.component').then(
            (m) => m.ReviewContinueComponent
          )
      },
      {
        path: '',
        redirectTo: 'bankForm',
        pathMatch: 'full',
      },
      {
        path: 'port-agent-form',
        loadComponent: () =>
          import('../../components/port-agent-form/port-agent-form.component').then(
            (m) => m.PortAgentFormComponent
          )
      },
    ],
  },
];
